package main

import (
	"fmt"
	"html"
	"net/http"
)

// HandleProductSearch handles the product search results page.
// It extracts the 'keyword' query parameter and displays it in the page title.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Escape the keyword to prevent XSS attacks
	escapedKeyword := html.EscapeString(keyword)

	// Set the content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Build and write the HTML response
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search</title>
</head>
<body>
    <h2>Search Results: %s</h2>
</body>
</html>`, escapedKeyword)

	w.Write([]byte(htmlContent))
}

func main() {
	// Register the handler for the search endpoint
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server on port 8080
	fmt.Println("Server starting on http://localhost:8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Printf("Server error: %v\n", err)
	}
}

