import (
	"fmt"
	"html"
	"net/http"
)

// HandleProductSearch handles the product search request and displays search results.
// It extracts the 'keyword' query parameter and displays it in the page title.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Get the keyword from query parameters
	keyword := r.URL.Query().Get("keyword")

	// Escape the keyword to prevent XSS attacks
	escapedKeyword := html.EscapeString(keyword)

	// Write the HTML response with the search keyword in the title
	fmt.Fprintf(w, "<h2>Search Results: %s</h2>", escapedKeyword)
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)
	http.ListenAndServe(":8080", nil)
}

