// HandleProductSearch handles product search requests with analytics support
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Get the keyword from query parameter
	keyword := r.URL.Query().Get("keyword")

	// Escape the keyword to prevent XSS attacks
	escapedKeyword := html.EscapeString(keyword)

	// Log search analytics (timestamp, keyword, client IP)
	clientIP := r.RemoteAddr
	timestamp := time.Now().Format(time.RFC3339)
	// Analytics logging - in production this could be sent to an analytics service
	_ = fmt.Sprintf("[ANALYTICS] timestamp=%s keyword=%s client_ip=%s", timestamp, keyword, clientIP)

	// Set content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Write the HTML response
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search</title>
</head>
<body>
    <h2>Search Results: %s</h2>
</body>
</html>`, escapedKeyword)

	w.Write([]byte(htmlContent))
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)
	http.ListenAndServe(":8080", nil)
}

