package main

import (
	"fmt"
	"html"
	"net/http"
	"time"
)

// HandleProductSearch handles product search requests with analytics support.
// It extracts the keyword from URL query parameters and displays search results.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Get the keyword from query parameter
	keyword := r.URL.Query().Get("keyword")

	// Escape the keyword to prevent XSS attacks
	escapedKeyword := html.EscapeString(keyword)

	// Set content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Record search timestamp for analytics
	searchTimestamp := time.Now().Format(time.RFC3339)

	// Write the HTML response with analytics support
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search Results</title>
    <script>
    // Analytics data layer
    window.analyticsData = {
        searchKeyword: "%s",
        searchTimestamp: "%s",
        pageType: "search_results"
    };
    </script>
</head>
<body>
    <h2>Search Results: %s</h2>
    <div id="search-analytics" data-keyword="%s" data-timestamp="%s" data-page="search"></div>
</body>
</html>`, escapedKeyword, searchTimestamp, escapedKeyword, escapedKeyword, searchTimestamp)

	w.Write([]byte(htmlContent))
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)
	http.ListenAndServe(":8080", nil)
}

