package main

import (
	"fmt"
	"html"
	"net/http"
)

// HandleProductSearch handles product search requests with analytics support.
// It extracts the 'keyword' query parameter and displays it in the page title.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Get the keyword from query parameters
	keyword := r.URL.Query().Get("keyword")

	// Escape the keyword to prevent XSS attacks
	escapedKeyword := html.EscapeString(keyword)

	// Set content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Write HTML response
	w.WriteHeader(http.StatusOK)

	// Build the HTML page with the search results title
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search</title>
</head>
<body>
    <h2>Search Results: %s</h2>
</body>
</html>`, escapedKeyword)

	w.Write([]byte(htmlContent))
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)

	fmt.Println("Server starting on :8080...")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Printf("Server error: %v\n", err)
	}
}

